class Solution:
    def minStartingIndex(self, s: str, pattern: str) -> int:
        m, n = len(s), len(pattern)
        diff_count = 0
        char_count = {}
        for c in pattern:
            char_count[c] = char_count.get(c, 0) + 1

        left = 0
        min_start_idx = float('inf')
        for right in range(m):
            if right - left == n:
                if s[left] != pattern[0]:
                    diff_count -= 1
                char_count[s[left]] = char_count.get(s[left], 0) + 1
                if char_count[s[left]] > 0:
                    diff_count -= 1
                left += 1

            if right - left < n:
                if s[right] != pattern[right - left]:
                    diff_count += 1
                char_count[s[right]] = char_count.get(s[right], 0) - 1
                if char_count[s[right]] < 0:
                    diff_count += 1

            if right - left + 1 == n and diff_count <= 1:
                min_start_idx = min(min_start_idx, left)

        return min_start_idx if min_start_idx != float('inf') else -1
```

